406	const MIXIN_KEY_ENC_TAB = [
407	  46, 47, 18, 2, 53, 8, 23, 32, 15, 50, 10, 31, 58, 3, 45, 35,
408	  27, 43, 5, 49, 33, 9, 42, 19, 29, 28, 14, 39, 12, 38, 41, 13,
409	  37, 48, 7, 16, 24, 55, 40, 61, 26, 17, 0, 1, 60, 51, 30, 4,
410	  22, 25, 54, 21, 56, 59, 6, 63, 57, 62, 11, 36, 20, 52, 44, 34
411	]
412	
413	let _wbiKey = null
414	let _wbiCacheTime = 0
415	const WBI_CACHE_TTL = 3600000
416	
417	async function getMixinKey() {
418	  if (_wbiKey && Date.now() - _wbiCacheTime < WBI_CACHE_TTL) return _wbiKey
419	
420	  const r = await fetch('https://api.bilibili.com/x/web-interface/nav', {
421	    headers: { Referer: 'https://www.bilibili.com' }
422	  })
423	  const j = await r.json()
424	  if (!j.data?.wbi_img) throw new Error('Failed to fetch WBI keys from nav')
425	
426	  const imgUrl = j.data.wbi_img.img_url
427	  const subUrl = j.data.wbi_img.sub_url
428	  const imgKey = imgUrl.split('/').pop().split('.')[0]
429	  const subKey = subUrl.split('/').pop().split('.')[0]
430	  const raw = imgKey + subKey
431	
432	  _wbiKey = MIXIN_KEY_ENC_TAB.map(i => raw[i]).join('').slice(0, 32)
433	  _wbiCacheTime = Date.now()
434	  return _wbiKey
435	}
436	
437	function signParams(params, mixinKey) {
438	  const sorted = Object.keys(params).sort()
439	  const query = sorted
440	    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
441	    .join('&')
442	  const wts = Math.floor(Date.now() / 1000)
443	  const w_rid = crypto.createHash('md5').update(query + mixinKey).digest('hex')
444	  return { ...params, wts, w_rid }
445	}
