491	    const plData = await plR.json()
492	    if (plData.code !== 0 || !plData.data?.[0]?.cid) {
493	      throw new Error(`pagelist failed: code=${plData.code}`)
494	    }
495	    const cid = plData.data[0].cid
496	    console.log(`[Bilibili] Got cid=${cid} for ${bvid}`)
497	
498	    // Step 2: WBI-sign the playurl request
499	    const mixinKey = await getMixinKey()
500	    const params = signParams({ bvid, cid, fnval: '4048', fnver: '0', fourk: '1', qn: '0' }, mixinKey)
501	    const paramsStr = Object.keys(params)
502	      .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
503	      .join('&')
504	
505	    const puUrl = `https://api.bilibili.com/x/player/wbi/playurl?${paramsStr}`
506	    console.log('[Bilibili] Fetching playurl with WBI signature...')
507	    const puR = await fetch(puUrl, {
508	      headers: { Referer: 'https://www.bilibili.com' },
509	      signal: AbortSignal.timeout(8000)
510	    })
511	    const puData = await puR.json()
512	    if (puData.code !== 0) {
513	      throw new Error(`playurl failed: code=${puData.code} ${puData.message || ''}`)
514	    }
515	
516	    const audio = puData.data?.dash?.audio?.[0]
