519	    }
520	
521	    console.log(`[Bilibili] Audio URL: ${audio.baseUrl.slice(0, 80)}...`)
522	    return {
523	      ok: true,
524	      url: audio.baseUrl,
525	      backupUrl: audio.backupUrl?.[0] || null,
526	      bandwidth: audio.bandwidth,
527	      duration: puData.data.timelength
528	    }
529	  } catch (e) {
