import { useState, useCallback, useRef, useEffect } from 'react'

/* ================================================================== */
/*  Bilibili Audio Stream — WBI-signed, stream:// protocol, Referer    */
/* ================================================================== */

let _player = null
function getPlayer() {
  if (!_player) {
    _player = new Audio()
    _player.crossOrigin = 'anonymous'
  }
  return _player
}

export default function useMusicController() {
  const [results, setResults] = useState([])
  const [searching, setSearching] = useState(false)
  const [currentTrack, setCurrentTrack] = useState(null)
  const [playing, setPlaying] = useState(false)
  const [error, setError] = useState(null)

  const currentRef = useRef(null)
  const resultsRef = useRef([])
  currentRef.current = currentTrack
  resultsRef.current = results

  async function playTrack(track) {
    if (!track?.bvid) return false
    setError(null)

    // Get WBI-signed audio URL from main process
    const r = await window.terminal?.bilibiliPlayurl?.({ bvid: track.bvid })
    if (!r?.ok) {
      setError(r?.error || 'Bilibili playurl failed')
      return false
    }

    const player = getPlayer()
    if (!player.paused) player.pause()
    player.src = `stream://audio?url=${encodeURIComponent(r.url)}`
    player.currentTime = 0
    try {
      await player.play()
      setCurrentTrack(track)
      setPlaying(true)
      return true
    } catch (e) {
      setError(e.message)
      return false
    }
  }

  // Auto-radio: move to next track in current results
  const autoRadio = useCallback(async () => {
    const prev = currentRef.current
    if (!prev) return

    const idx = resultsRef.current.findIndex((t) => t.bvid === prev.bvid)
    const next = resultsRef.current[idx + 1] || resultsRef.current[0]
    if (next && next.bvid !== prev.bvid) {
      console.log('[Radio] Next up:', next.title)
      await playTrack(next)
    } else {
      console.log('[Radio] No more tracks')
    }
  }, [])

  useEffect(() => {
    const player = getPlayer()
    player.addEventListener('ended', autoRadio)
    return () => player.removeEventListener('ended', autoRadio)
  }, [autoRadio])

  const search = useCallback(async (query) => {
    if (!query.trim()) { setResults([]); return }
    setSearching(true)
    setError(null)
    try {
      const r = await window.terminal?.bilibiliSearch?.({ keyword: query, limit: 20 })
      if (!r?.ok) throw new Error(r?.error || 'Search failed')
      setResults(r.results || [])
    } catch (e) {
      setResults([])
      setError(e.message)
    }
    setSearching(false)
  }, [])

  const play = useCallback(async (track) => {
    setError(null)
    await playTrack(track)
  }, [])

  const pause = useCallback(() => { getPlayer().pause(); setPlaying(false) }, [])
  const resume = useCallback(() => { getPlayer().play().catch(() => {}); setPlaying(true) }, [])
  const stop = useCallback(() => {
    const p = getPlayer()
    p.pause(); p.currentTime = 0
    setPlaying(false); setCurrentTrack(null)
  }, [])

  return { search, results, searching, play, pause, resume, stop, playing, currentTrack, error }
}

import { useState, useRef, useEffect } from 'react'

const TIER_NAMES = ['Deep Space', 'Particle Stream', 'Interstellar']

function fileName(url) {
  if (!url) return '—'
  try { return decodeURIComponent(url.split('/').pop()) } catch (_) { return url }
}

export default function TopMenuBar({
  currentTime = '',
  musicOn,
  onToggleMusic,
  currentTier = 0,
  audioMap = {},
  masterVolume = 0.75,
  mode = 'dynamic',
  onChangeTrack,
  onVolumeChange,
  onModeChange,
  onStaticSelect,
  onToggleSearch,
  searchOpen,
  musicPlaying,
  musicTrack,
  onMusicPause,
  onMusicResume
}) {
  const [audioOpen, setAudioOpen] = useState(false)
  const panelRef = useRef(null)
  const fileRefs = useRef([null, null, null])

  useEffect(() => {
    if (!audioOpen) return
    function handler(e) {
      if (panelRef.current && !panelRef.current.contains(e.target)) setAudioOpen(false)
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [audioOpen])

  function handleFile(tier, e) {
    const file = e.target.files?.[0]
    if (file) onChangeTrack?.(tier, file)
    e.target.value = ''
  }

  const isStatic = mode === 'static'

  return (
    <div
      className="h-12 glass-panel border-b border-cosmos-border/30 flex items-center justify-between px-4 shrink-0 relative"
      style={{ WebkitAppRegion: 'drag' }}
