node -e "
const fs = require('fs');
const path = require('path');
const dir = process.env.HOME + '/.claude/projects/E--GitHub-tools-galaxy-terminal';
const files = fs.readdirSync(dir).filter(f => f.endsWith('.jsonl'));

files.forEach(file => {
  const outFile = path.join(dir, file.replace('.jsonl', '.md'));
  const lines = fs.readFileSync(path.join(dir, file), 'utf8').split('\n').filter(Boolean);
  let md = '# Session: ' + file.replace('.jsonl', '') + '\n\n';

  lines.forEach(line => {
    try {
      const obj = JSON.parse(line);
      if (!obj.message || !obj.message.role) return;

      const content = obj.message.content;
      if (!content) return;

      // Skip meta/system messages
      if (obj.isMeta || obj.type === 'attachment') return;

      const role = obj.message.role === 'user' ? '🧑 你' : '🤖 Claude';
      const text = (typeof content === 'string') 
        ? content 
        : content.map(c => {
            if (c.type === 'text') return c.text;
            if (c.type === 'tool_use') return '[调用工具: ' + c.name + ']';
            if (c.type === 'thinking') return '[思考中...]';
            return '';
          }).filter(Boolean).join('\n');

      if (text.trim()) {
        md += '## ' + role + '\n\n' + text + '\n\n---\n\n';
      }
    } catch(e) {}
  });

  fs.writeFileSync(outFile, md);
  console.log('Generated: ' + path.basename(outFile));
});
"
